#include <stdio.h>
#include <stdlib.h>

typedef struct {int start; int end;} Interval;

int cmp(const void *a, const void *b) {
    const Interval *i1 = (const Interval *)a;
    const Interval *i2 = (const Interval *)b;
    return i1->start - i2->start;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        if (N == 0) { printf("\n"); continue; }
        Interval *arr = malloc(N * sizeof(Interval));
        for (int i = 0; i < N; ++i) scanf("%d %d", &arr[i].start, &arr[i].end);
        qsort(arr, N, sizeof(Interval), cmp);
        int curS = arr[0].start, curE = arr[0].end;
        for (int i = 1; i < N; ++i) {
            if (arr[i].start <= curE) {
                if (arr[i].end > curE) curE = arr[i].end;
            } else {
                printf("[%d,%d] ", curS, curE);
                curS = arr[i].start; curE = arr[i].end;
            }
        }
        printf("[%d,%d]\n", curS, curE);
        free(arr);
    }
    return 0;
}

