import java.io.*;
import java.util.*;

public class Main {
    static class Interval {
        int start, end;
        Interval(int s, int e){start=s; end=e;}
    }
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder out = new StringBuilder();
        int T = Integer.parseInt(br.readLine().trim());
        for (int tc = 0; tc < T; ++tc) {
            String line;
            while ((line = br.readLine()) != null && line.trim().isEmpty()) {}
            int N = Integer.parseInt(line.trim());
            if (N == 0) { out.append('\n'); continue; }
            Interval[] arr = new Interval[N];
            for (int i = 0; i < N; i++) {
                StringTokenizer st = new StringTokenizer(br.readLine());
                int s = Integer.parseInt(st.nextToken());
                int e = Integer.parseInt(st.nextToken());
                arr[i] = new Interval(s, e);
            }
            Arrays.sort(arr, Comparator.comparingInt(i -> i.start));
            int curS = arr[0].start, curE = arr[0].end;
            for (int i = 1; i < N; i++) {
                if (arr[i].start <= curE) {
                    curE = Math.max(curE, arr[i].end);
                } else {
                    out.append('[').append(curS).append(',').append(curE).append(']').append(' ');
                    curS = arr[i].start; curE = arr[i].end;
                }
            }
            out.append('[').append(curS).append(',').append(curE).append(']').append('\n');
        }
        System.out.print(out.toString());
    }
}

